import os
import json


class StorageError(Exception):
    """Raised when a storage operation fails."""
    def __init__(self, key, message, cause=None):
        self.key = key
        self.message = message
        self.cause = cause
        super().__init__(f"Storage[{key}]: {message}")


def open_store(path, backend="file", **kwargs):
    """Open or create a storage instance."""
    from .backend import FileBackend, MemoryBackend
    if backend == "file":
        return FileBackend(path, **kwargs)
    elif backend == "memory":
        return MemoryBackend(**kwargs)
    else:
        raise StorageError(path, f"Unknown backend: {backend}")

