from .core import StorageError, open_store


class ConnectionPool:
    """Pool of storage connections."""

    def __init__(self, path, size=3):
        self.path = path
        self._stores = [open_store(path, backend="memory") for _ in range(size)]
        self._available = list(self._stores)

    def acquire(self):
        if not self._available:
            raise StorageError("pool", "No connections available")
        return self._available.pop()

    def release(self, store):
        self._available.append(store)

    def size(self):
        return len(self._stores)

