from .core import StorageError, open_store


class Migrator:
    """Migrate data between storage backends."""

    def __init__(self, source_path, dest_path):
        self._source = open_store(source_path, backend="memory")
        self._dest = open_store(dest_path, backend="memory")

    def migrate_key(self, key):
        try:
            value = self._source.get(key)
            self._dest.put(key, value)
        except StorageError as e:
            raise StorageError(key, f"Migration failed: {e.message}", cause=e)

    def migrate_all(self):
        errors = []
        for key in self._source.keys():
            try:
                self.migrate_key(key)
            except StorageError as e:
                errors.append(e)
        return errors

