from .core import StorageError


class Compactor:
    """Compact storage by removing deleted entries."""

    def __init__(self, store):
        self._store = store

    def compact(self, keys_to_remove):
        removed = 0
        errors = []
        for key in keys_to_remove:
            try:
                self._store.delete(key)
                removed += 1
            except StorageError as e:
                errors.append(e)
        return {"removed": removed, "errors": len(errors)}

