from .core import StorageError, open_store


class Replicator:
    """Replicate data across multiple stores."""

    def __init__(self, paths):
        self._replicas = [open_store(p, backend="memory") for p in paths]

    def write(self, key, value):
        errors = []
        for replica in self._replicas:
            try:
                replica.put(key, value)
            except Exception as e:
                errors.append(StorageError(key, f"Replication failed: {e}", cause=e))
        if errors:
            raise errors[0]

    def read(self, key):
        for replica in self._replicas:
            try:
                return replica.get(key)
            except StorageError:
                continue
        raise StorageError(key, "Key not found in any replica")

