from .core import StorageError, open_store


class SnapshotManager:
    """Manage point-in-time snapshots."""

    def __init__(self, store):
        self._store = store
        self._snapshots = {}

    def create_snapshot(self, name):
        snap = open_store(f"/tmp/snap_{name}", backend="memory")
        for key in self._store.keys():
            try:
                value = self._store.get(key)
                snap.put(key, value)
            except StorageError as e:
                raise StorageError(key, f"Snapshot failed: {e.message}", cause=e)
        self._snapshots[name] = snap
        return snap

    def restore_snapshot(self, name):
        if name not in self._snapshots:
            raise StorageError(name, "Snapshot not found")
        snap = self._snapshots[name]
        for key in snap.keys():
            value = snap.get(key)
            self._store.put(key, value)

