from .core import StorageError


class IndexManager:
    """Maintain secondary indexes over stored data."""

    def __init__(self, store):
        self._store = store
        self._indexes = {}

    def create_index(self, name, key_func):
        self._indexes[name] = {"func": key_func, "data": {}}

    def index_key(self, key):
        try:
            value = self._store.get(key)
        except StorageError:
            return
        for idx_name, idx in self._indexes.items():
            idx_key = idx["func"](value)
            if idx_key not in idx["data"]:
                idx["data"][idx_key] = []
            idx["data"][idx_key].append(key)

    def lookup(self, index_name, idx_key):
        if index_name not in self._indexes:
            raise StorageError(index_name, "Index not found")
        return self._indexes[index_name]["data"].get(idx_key, [])

